'use strict';

/**
 * Sliding-window rate limiter for Express.
 *
 * TRUE sliding window: each client's request timestamps are stored, and on
 * every request we evict timestamps older than `windowMs` before counting.
 * There is no fixed-interval reset — the window continuously "slides" with
 * the current time.
 *
 * @param {Object}  [options]
 * @param {number}  [options.windowMs=60000]   Window size in ms (default 1 min).
 * @param {number}  [options.maxRequests=100]  Max requests allowed per window.
 * @param {Function}[options.keyGenerator]     (req) => string. Defaults to req.ip.
 * @returns {Function} Express middleware with a `.close()` method attached.
 */
function createRateLimiter(options = {}) {
  const windowMs = options.windowMs ?? 60000;
  const maxRequests = options.maxRequests ?? 100;
  const keyGenerator = options.keyGenerator ?? ((req) => req.ip);

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  // Map<clientKey, number[]>  — sorted ascending list of request timestamps (ms).
  const hits = new Map();

  /** Remove timestamps at the front of `arr` that fall outside the window. */
  function evictExpired(arr, windowStart) {
    // Timestamps are pushed in chronological order, so the oldest are at the
    // front. We can splice off the expired prefix in one shot.
    let i = 0;
    while (i < arr.length && arr[i] <= windowStart) i++;
    if (i > 0) arr.splice(0, i);
    return arr;
  }

  const middleware = function rateLimiter(req, res, next) {
    const now = Date.now();
    const windowStart = now - windowMs;
    const key = keyGenerator(req);

    let timestamps = hits.get(key);
    if (!timestamps) {
      timestamps = [];
      hits.set(key, timestamps);
    }

    // Slide the window: drop anything older than windowMs.
    evictExpired(timestamps, windowStart);

    const limit = maxRequests;

    if (timestamps.length >= limit) {
      // ----- REJECT -----
      // The window frees up one slot when the OLDEST in-window request expires.
      const oldest = timestamps[0];
      const resetMs = oldest + windowMs;            // when a slot becomes free
      const retryAfterSec = Math.max(1, Math.ceil((resetMs - now) / 1000));

      res.setHeader('X-RateLimit-Limit', limit);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));
      res.setHeader('Retry-After', retryAfterSec);

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // Do NOT call next().
    }

    // ----- ALLOW -----
    timestamps.push(now);

    const remaining = Math.max(0, limit - timestamps.length);
    // The window fully clears windowMs after the oldest current request.
    const resetMs = timestamps[0] + windowMs;

    res.setHeader('X-RateLimit-Limit', limit);
    res.setHeader('X-RateLimit-Remaining', remaining);
    res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));

    next();
  };

  // ---- Periodic cleanup to bound memory ----
  // Removes IPs that have had no requests within the last windowMs.
  const cleanupInterval = setInterval(() => {
    const windowStart = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      evictExpired(timestamps, windowStart);
      if (timestamps.length === 0) {
        hits.delete(key);
      }
    }
  }, 60000);

  // Don't let the cleanup timer keep the Node process alive on its own.
  if (typeof cleanupInterval.unref === 'function') {
    cleanupInterval.unref();
  }

  // Allow callers to stop the timer explicitly (tests, graceful shutdown).
  middleware.close = function close() {
    clearInterval(cleanupInterval);
    hits.clear();
  };

  return middleware;
}

module.exports = createRateLimiter;
module.exports.createRateLimiter = createRateLimiter;
