## Usage example

```js
// server.js
const express                = require('express');
const { createRateLimiter } = require('./rate-limiter');

const app = express();

// ── CRITICAL: set trust proxy BEFORE mounting any IP-based middleware ────────
//
//   '1'  → trust the single reverse proxy directly in front of this process
//           (e.g. Nginx on the same host).  Express will then read req.ip from
//           the leftmost X-Forwarded-For entry instead of the socket address.
//
//   Without this, every client appears to come from the proxy's IP, so all
//   traffic is throttled as a single client.
app.set('trust proxy', 1);

// ── Create a limiter ─────────────────────────────────────────────────────────
const apiLimiter = createRateLimiter({
  windowMs:    60 * 1000, // 60-second sliding window
  maxRequests: 100,       // ≤100 requests per window per IP
});

// ── Mount it (route-scoped here; use app.use(limiter) for global) ────────────
app.use('/api', apiLimiter);

app.get('/api/data', (_req, res) => {
  res.json({ ok: true });
});

// ── Start server ─────────────────────────────────────────────────────────────
const server = app.listen(3000, () => console.log('Listening on :3000'));

// ── Graceful shutdown ─────────────────────────────────────────────────────────
function shutdown() {
  apiLimiter.close();           // stop the 60-s cleanup interval
  server.close(() => {
    console.log('Server closed cleanly');
    process.exit(0);
  });
}
process.on('SIGTERM', shutdown);
process.on('SIGINT',  shutdown);
```

